INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (1, 'Спагети Карбонара', 'Паста', '1. Сварете спагетите в подсолена вода до al dente.
    2. Запържете бекона на кубчета до хрупкавост.
    3. Разбийте яйцата с настърганото пармезан и черен пипер.
    4. Отцедете пастата, запазете чаша от водата.
    5. Смесете пастата с бекона извън огъня.
    6. Добавете яйчената смес и разбъркайте бързо, като добавяте малко от запазената вода.', 20, 4, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-10 10:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (2, 'Гръцка салата', 'Салата', '1. Нарежете доматите и краставицата на едри парчета.
    2. Нарежете червения лук на полукръгове.
    3. Добавете маслини и нарязан зелен пипер.
    4. Наредете сиренето фета отгоре на цяло парче.
    5. Полейте с екстра върджин зехтин.
    6. Поръсете с риган, сол и черен пипер.', null, 2, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-11 11:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (3, 'Пилешка супа с юфка', 'Супа', '1. Сварете пилето в 2 литра вода с целина, морков и лук.
    2. Извадете пилето, оставете да изстине и го нарежете на парченца.
    3. Прецедете бульона и го върнете на огъня.
    4. Добавете нарязаните зеленчуци и варете 10 минути.
    5. Добавете юфката и варете още 8 минути.
    6. Върнете пилето, добавете сол и магданоз.', 60, 6, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-12 09:30:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (4, 'Шоколадов фондан', 'Десерт', '1. Разтопете шоколада и маслото на водна баня.
    2. Разбийте яйцата със захарта до пухкава смес.
    3. Добавете брашното и разбъркайте.
    4. Смесете с шоколадовата смес.
    5. Намажете рамекини с масло и поръсете с какао.
    6. Изпечете на 200°C за точно 12 минути — центърът трябва да е течен.', 12, 4, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-13 14:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (5, 'Маргарита пица', 'Пица', '1. Смесете брашното, маята, солта, зехтина и водата и омесете тесто.
    2. Оставете да втаса 1 час на топло място.
    3. Разточете тестото на тънка основа.
    4. Намажете с доматен сос.
    5. Наредете парчета моцарела.
    6. Печете на 250°C за 10-12 минути до хрупкава коричка.
    7. Гарнирайте с пресен босилек.', 12, 3, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-14 12:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (6, 'Тиквена крем супа', 'Супа', 'променент текст', 35, 4, '', '2024-01-15 10:30:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (7, 'Банички със сирене', 'Закуска', '1. Размесете сиренето с яйцата и содата бикарбонат.
    2. Намажете кора фило с разтопено масло.
    3. Поставете пълнеж в единия край на кората.
    4. Навийте на руло или нагънете на триъгълник.
    5. Наредете в тава, намажете с разбито яйце.
    6. Печете на 180°C за 25-30 минути до златисто.', 30, 8, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-16 08:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (8, 'Тирамису', 'Десерт', '1. Разбийте жълтъците със захарта до бяла пухкава крема.
    2. Добавете маскарпонето и разбъркайте внимателно.
    3. Разбийте белтъците на сняг и ги добавете към крема.
    4. Накиснете савоярдите в студено еспресо за 2 секунди.
    5. Наредете слой бишкоти, покрийте с крема, повторете.
    6. Поръсете с какао и охладете минимум 4 часа.', null, 6, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-17 15:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (9, 'Пържен ориз с зеленчуци', 'Основно ястие', '1. Сварете ориза предния ден и охладете.
    2. Загрейте уок на силен огън с олио.
    3. Запържете чесъна и джинджифила за 30 секунди.
    4. Добавете зеленчуците и запържете 3-4 минути.
    5. Добавете ориза и разбъркайте добре.
    6. Добавете соев сос и сусамово олио, разбъркайте.
    7. Направете кладенче, разбийте яйцата вътре и разбъркайте.', 15, 4, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-18 13:00:00');
INSERT INTO Recipes (Id, Title, Category, Instructions, CookTimeMinutes, Servings, ImageUrl, CreatedAt) VALUES (10, 'Ябълков щрудел', 'Десерт', '1. Обелете и нарежете ябълките на тънки резени.
    2. Смесете ябълките с захарта, канелата и стафидите.
    3. Разточете фино кори фило върху кърпа.
    4. Намажете кората с разтопено масло.
    5. Наредете пълнежа в единия край.
    6. Завийте щрудела с помощта на кърпата.
    7. Печете на 190°C за 35-40 минути до златисто.
    8. Поръсете с пудра захар преди сервиране.', 40, 6, 'https://media.istockphoto.com/id/1395273094/photo/close-up-on-a-woman-cooking-at-home-following-an-online-recipe.jpg?s=612x612&w=0&k=20&c=UrqNQmMlccycK5mmMaH5-WA0B1nH2NCHM0pmIHODF2o=', '2024-01-19 16:00:00');
